INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-392, '深圳豪石生物科技有限公司', NULL, NULL, NULL, '广东省深圳市宝安区新桥街道黄埔社区洪田路155号创新智慧港2栋七层', NULL, NULL, NULL, 'http://www.haoshibio.com/', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '深圳豪石生物科技有限公司（以下简称“豪石生物”）是由 一批留美归国专业技术人员于2017年创建，2019年在深圳市宝安区创新智慧港2栋7层建成细胞库和符合国家GMP标准的细胞治疗产品的研 发、生产实验室。    豪石生物专注细胞储存，细胞治疗，并开展免疫细胞治疗肿 瘤的研究、转化及临床应用。豪石生物已与国内外多个科研机构的专家、教授、学者合作，开展单靶点CAR-T、双靶点CAR-T、CTL等肿瘤 治疗技术的临床前期研究。    豪石生物持续引进国内外生物医药领域专业人才，为客户提 供专业化的服务，为提升企业的国际竞争力奠定了基础。', '2023-01-31 11:42:08', '2023-01-31 11:42:08', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
