VALUES (SPN-396, '北京门罗生物科技有限公司', NULL, NULL, NULL, '北京市昌平区奇点中心', NULL, NULL, NULL, 'https://www.menlobiotech.com', '4', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '北京门罗生物科技有限公司是在第三代基因编辑技术及iPSC干细胞技术研究转化成果上建立起来的新型免疫治疗及基因治疗企业。     公司已成功开发了具有自主知识产权的高精准基因编辑技术平台及iPSC干细胞诱导分化技术平台，研发出多款通 用型细胞免疫治疗及基因治疗产品，可以为血液瘤和实体瘤提供可负担起的、更有效的治疗方案。     公司已完成多款通用型细胞免疫治疗产品的临床前研发，产品已进入生产工艺开发及优化。同时目前正在选择合适的PI 和医院计划开展探索性研究者发起的临床研究(Investigator Initiated Trial, IIT)。', '2023-01-31 13:52:11', '2023-01-31 13:52:11', 'SYSTEM', 'SYSTEM');
