VALUES (SPN-473, '北京瑷格干细胞科技有限公司', NULL, NULL, NULL, '北京市大兴区礼贤镇元平北路1号自贸试验区大兴机场片区自贸创新服务中心东区1层E107', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '瑷格干细胞项目技术源自国内相关领域顶尖专家多年临床诊疗及技术的开发积累。目前，公司围绕硬皮病、创面修复、皮肤光老化、皮肤衰老等领域布局了数个脂肪间充质干细胞管线产品。    瑷格干细胞聚焦并致力于干细胞药物研发，以北京协和医院临床研究及专利技术为依托，是临空区首批科技创新企业。下一步瑷格干细胞将全力做好药品临床试验相关工作，进一步助力临空区生命健康产业发展。', '2023-02-03 13:43:43', '2023-02-03 13:43:43', 'SYSTEM', 'SYSTEM');
