VALUES (SPN-721, '杭州多禧生物', NULL, NULL, NULL, '浙江杭州市杭州经济技术开发区6号大街260 号中自科技园13栋', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '于2012年12月31日创立。公司拥有自主知识产权的ADC药物平台涵盖：连接技术方面，拥有新型智能化连接子（包括定点偶联）共约50余种；小分子细胞毒性化合物方面，拥有5大类，共约101余种分子，涵盖抗微管蛋白（Tubulysin）、DNA小沟槽结合体（PBD）、DNA烷基化类(Duocarmycin)、RNA聚合酶抑制剂类(Amanitin)、拓扑酶抑制剂类(CPT)等；抗体工程方面，建立了完善的抗体构建和生产工艺。', '2023-02-03 13:54:11', '2023-02-03 13:54:11', 'SYSTEM', 'SYSTEM');
