INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-723, '西安泰科迈医药科技股份有限公司', NULL, NULL, NULL, '西安市高新技术开发区锦业路69号瞪羚谷C区1号创业研发园B座7楼', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '成立于2011年，是一家专业从事药品研究和技术开发的高新技术企业。主营业务：抗肿瘤新药研发，化学原料药开发，化学仿制药研发，仿制药一致性评价技术服务，中药开发及技术服务，药物临床研究服务。多年来以药品研发为己任，以打造成国内一流的药物研发机构和专业的药品服务商为目标。在癌症、心脑血管、肠胃道、免疫力低下、神经系统等疾病领域，应用纳米递释技术、缓控释技术、逆向工程技术先后为100余家企业研发申报注册中药、化药仿制药、保健品等药品201多个。公司立足于化药原料药开发、仿制药开发、仿制药一致性评价、尤其是对缓控', '2023-02-03 13:54:11', '2023-02-03 13:54:11', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-724, '杭州百诚医药科技有限公司', NULL, NULL, NULL, '杭州市滨江区东冠路611号金盛科技园8号楼3层', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司业务涵盖药物发现、药学研究、临床研究、注册申请等药物研发主要环节，其中在药学研究和生物等效性试验（简称BE临床试验）研究服务上具有核心竞争优势。', '2023-02-03 13:54:11', '2023-02-03 13:54:11', 'SYSTEM', 'SYSTEM');
