INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-726, '博生吉医药科技有限公司', NULL, NULL, NULL, '苏州工业园区星湖街218号生物纳米园B1-413', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '2010年5月32日注册成立在苏州工业园区，可开展国际一流水平的细胞治疗新技术的研发，涵盖抗原结合域的开发、CAR结构的优化、CAR-T细胞的功能测试、直至体内药效试验的验证。拥有先进的CAR结构及功能验证平台、CAR-T细胞体内药效验证平台、Safeγ UCAR-γδT细胞药物开发平台、iPSC诱导的现货型细胞药物开发平台、以及NanoBa双特异抗体研发平台。  公司专注于开发具有国际领先水平的突破性First-in-class和Best-in-class CAR-T细胞药物，已有多个细胞产品进入POC', '2023-02-03 13:54:11', '2023-02-03 13:54:11', 'SYSTEM', 'SYSTEM');
