VALUES (SPN-728, '苏州晶云药物科技有限公司', NULL, NULL, NULL, '苏州工业园区星湖街218号生物医药产业园B4-302', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '成立于2011年，一直专注于为全球创新药公司提供国际领先的晶型研究和制剂研发及生产服务。我们依托Molecule-Material-Medicine（MMM）策略帮助创新药公司开发适合于其药物分子的最佳晶型和制剂。', '2023-02-03 13:54:11', '2023-02-03 13:54:11', 'SYSTEM', 'SYSTEM');
