VALUES (SPN-730, '苏州思坦维生物技术有限责任公司', NULL, NULL, NULL, '江苏省苏州工业园区星湖街218号生物纳米园C12', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '肿瘤药', '2023-02-03 13:54:12', '2023-02-03 13:54:12', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-731, '英派药业有限公司', NULL, NULL, NULL, '江苏省南京市江宁区秣陵街道景枫中心写字楼2507室', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司产品管线包括PARP抑制剂（senaparib/ IMP4297）、Wee1抑制剂（IMP7068）以及多个其他DDR靶点抑制剂。其中最成熟的研发项目PARP抑制剂（senaparib/ IMP4297）在全球范围包含中国在内已开展卵巢癌、前列腺癌、小细胞肺癌等适应症的临床II/III期研究，早期数据显示了比同类药物更优的安全性及更宽的治疗窗口。Wee1抑制剂（IMP7069）已在包括美国、中国在内的全球多个国家及地区开展I期临床研究。', '2023-02-03 13:54:12', '2023-02-03 13:54:12', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-732, '浙江经纬药业有限公司', NULL, NULL, NULL, '浙江省常山县新都工业园区翁佳路20号', NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司共有六个剂型： 1、固体制剂（胶囊剂、片剂、颗粒剂） 2、软膏剂、乳膏剂（含激素类） 4、原料药（酞丁安）。 公司生产的内销品种有复方猴头胶囊、复方猴头颗粒、萘普生分散片、小儿氨酚黄那敏颗粒、清肝颗粒、木糖醇颗粒、酞丁安乳膏、复方薄荷脑软膏、咪康唑氯倍他索乳膏、复方醋酸地塞米松乳膏，酞丁安原料药。其中复方猴头胶囊是全国独家品种。复方薄荷脑软膏是少数持有国药准字文号的药品生产企业。酞丁安（原料药）也是国内少有的生产厂家', '2023-02-03 13:54:12', '2023-02-03 13:54:12', 'SYSTEM', 'SYSTEM');
