VALUES (SPN-1331, '青岛奥克生物开发有限公司', NULL, NULL, NULL, '山东省青岛市高新区广博路3号', NULL, NULL, NULL, 'http://jm.qdstemcell.com/', '4', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '青岛奥克生物开发有限公司是一家集干细胞保存、研究、生物技术产品研发及生物制药于一体的生物公司。2009年，山东省卫生厅批准奥克生物与青医附院联合成立“山东省人类脐带间充质干细胞库”，成为全省范围内获得此项资质的专业干细胞保存机构，目前主营业务为人类间充质干细胞储存服务，可实现年处理并储存干细胞万余份。2011年投资3.4亿，占地4.2公顷，建设集科研、临床医疗、生物医药研发、生物技术成果转化于一体的干细胞与生物诊疗基地。奥克生物干细胞产业化基地拥有干细胞储存库、B+A式层流生产车间、研发中心、质控中心、SPF级实验动物房、国际医学中心、成果转化中心、学术交流中心等', '2023-07-07 09:48:37', '2023-07-07 09:48:37', 'SYSTEM', 'SYSTEM');
