VALUES (SPN-1337, '沈阳何氏眼产业集团有限公司', NULL, NULL, NULL, '沈阳市东陵区泗水街66号', NULL, NULL, NULL, 'http://www.hsyk024.com/', '4', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '辽宁何氏眼科医院集团股份有限公司（下称“何氏眼科”）由留学归国眼科医学博士、全国防盲技术指导组副组长、国际防盲协会理事会常务理事、国际眼科基金会常务理事何伟及其团队创办，是一家集医教研于一体，采用三级眼健康医疗服务模式，致力于全生命周期眼健康管理的集团型连锁眼健康服务机构。在白内障、青光眼、玻璃体视网膜病变、干眼、中医、屈光不正等诊疗服务项目上拥有丰富的临床经验和突出的技术优势；同时，在基因、干细胞诊疗领域不断深耕创新，探索出以基因、干细胞技术引领的精准医疗眼科新模式，在遗传性视网膜劈裂症的相关实验中取得突破性进展。', '2023-07-19 16:32:02', '2023-07-19 16:32:02', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1338, '科兴生物制药股份有限公司', NULL, NULL, NULL, '山东省济南市章丘区埠村街道创业路2666号', NULL, NULL, NULL, 'http://www.kexing.com/', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '科兴制药（股票代码：688136）是一家主要从事重组蛋白药物和微生态制剂的研发、生产、销售一体化的创新型生物制药企业，专注于抗病毒、肿瘤与免疫、血液、消化、退行性疾病等治疗领域，打造新型蛋白、新型抗体、核酸药物等前沿生物技术平台，坚持“创新+国际化”双轮驱动的平台型发展模式，同时探索生物技术在大健康领域的广泛应用，积极培育孵化新产业，致力于成为高品质生物药领导者，服务全球患者。    主要产品包括重组蛋白药物“人促红素（依普定）”、“人干扰素α1b（赛若金）”、“人粒细胞刺激因子（白特喜）”微生态制剂药物“酪酸梭菌二联活菌（常乐康）”、独家中成药“克癀胶囊”、化学药“恩替卡韦（赛苷苏）”以及引进高端复杂制剂“白蛋白紫杉醇”、单抗类药物“英夫利西单抗（类停）”、“贝伐珠单抗”和“阿达木单抗”。', '2023-07-19 16:40:16', '2023-07-19 16:40:16', 'SYSTEM', 'SYSTEM');
