VALUES (SPN-1408, '武汉光谷中源药业有限公司', NULL, NULL, NULL, '湖北省武汉市江夏区高新大道818号高科医疗器械园b14栋1层', NULL, NULL, NULL, NULL, '4', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '武汉光谷中源药业有限公司（以下简称“中源药业”）为中源协和细胞基因工程股份有限公司（股票代码：600645）旗下全资子公司，长期专注细胞治疗药物研发。截止目前，中源药业旗下VUM02注射液已获得6个适应症的临床默示许可，位居全国间充质干细胞类新药IND获批数量首位！此外，在开展干细胞临床研究备案项目7个适应症覆盖肝、肺、肾等多个组织器官。中源药业旗下有多条干细胞药物研发管线，是极具创新及科研实力的企业。', '2023-12-11 09:51:59', '2023-12-11 09:51:59', 'SYSTEM', 'SYSTEM');
