VALUES (SPN-1442, '山东壹瑞特生物科技有限公司', NULL, NULL, NULL, '中国（山东）自由贸易试验区济南片区经十东路33688号综合保税区内聚轩厂房B座（21B）一层', NULL, NULL, NULL, 'http://www.sdelad.com/', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', 'ELAD生物人工肝具有净化血液，促进肝脏细胞修复的强大功能，它以四个ELAD生物细胞反应器替代患者肝脏，参与代谢、合成，解毒和血液净化；并且ELAD生物人工肝可以连续治疗至少72小时以上（最长可连续治疗长达10天），帮助病人自身衰竭的肝脏得到修复和再生，避免昂贵的肝移植和终身使用抗排斥药，为肝衰竭患者提供全新的治疗方法和解决方案。    目前，ELAD生物人工肝是唯一完成III期临床的器械--中国69例临床试验，美国+欧洲558例临床试验。', '2024-03-11 14:58:18', '2024-03-11 14:58:18', 'SYSTEM', 'SYSTEM');
