INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1446, '山东省齐鲁细胞治疗工程技术有限公司', NULL, NULL, NULL, '山东省济南市高新区航天大道5999号济南综合保税区海关监管仓库配套办公区117-B3（经营场所：港源六路银丰生物科技园一期二层201室）', NULL, NULL, NULL, 'http://www.qlxbsw.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司情况：山东省齐鲁细胞治疗工程技术有限公司，成立于2011年， 隶属于银丰集团旗下，是一家细胞存储、细胞制备、细胞科学技术研究于一体的高新技术企业。 公司建成占地2000余平米的中心实验室和7家分部实验室，拥有成熟完备的集细胞制备、存储、检验、研发于一体的综合性细胞生物技术工程体系。近年来，齐鲁细胞治疗一直致力于干细胞和免疫细胞相关的培养、存储、科研和临床转化等工作。  项目情况：齐鲁细胞研发部马贺然博士团队研发的人脐带间充质干细胞注射液（代号YFQLXB-UC01）于2024年3月11日收到国家药品监督管理局核准签发的《药物临床试验批准通知书》，适应症为失代偿期肝硬化。目前与国内多家临床机构联合开展的6项国家级干细胞临床项目均成功通过卫健委备案；参与的《脐带间充质干细胞及其外泌体促进骨髓组织损伤修复及功能重建的临床研究》课题，获得“十四五”国家重点专项立项。', '2024-03-15 15:50:54', '2024-03-15 15:50:54', 'SYSTEM', 'SYSTEM');
