VALUES (SPN-1457, '广州来恩生物医药有限公司', NULL, NULL, NULL, '广州市黄埔区中新智慧一街5号806房807房808房', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', NULL, '2024-06-24 10:15:03', '2024-06-24 10:15:03', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1458, '北京慧心医谷生物科技有限责任公司', NULL, NULL, NULL, '北京市昌平区生命科学园生命园路奥瑞金大厦南楼', NULL, NULL, NULL, 'www.wiseheartmed.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '慧心医谷成立于2021年7月，致力于将具有自主知识产权的国际领先诱导神经干细胞技术应用于神经系统疾病的药物研究和创新疗法开发。首个在研管线是将诱导神经干细胞（iNSCs）分化得到的多巴胺能神经前体细胞（iNSC-DAP）注射液，用于帕金森病的治疗。该国际领先的I类生物新药，经颅内注射，可以替代、补充坏死的多巴胺能神经元，实现脑内生理性分泌多巴胺，以期达到一次移植，长期有效，缓解症状，遏制病情进展的目的。2023年7月，全球首例使用iNSC-DAP自体细胞移植治疗帕金森病的神经外科手术在首都医科大学宣武医院成功完成', '2024-06-25 08:58:19', '2024-06-25 08:58:19', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1459, '北京第一生物化学药业有限公司', NULL, NULL, NULL, '北京市朝阳区呼家楼街道东三环北路38号院好世界商业广场2层L226君诊门诊部', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司情况：北京第一生物化学药业有限公司始建于1958年，原为北京大学校办药厂，是以生产经营生化药品为主的技术公司，也是中国历史悠久的生物化学制药公司。目前在创新药，改良型新药，细胞药物方面进行研究开发。  项目情况：基于围产期组织间充质干细胞，将在抗衰老、皮肤相关、炎症相关等几个领域开展一系列满足临床需求的干细胞药物开发。本次拟洽谈项目为围产期脐血干细胞治疗变应性鼻炎的IND申报项目；', '2024-06-25 09:05:34', '2024-06-25 09:05:34', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1460, '梁健霖', NULL, NULL, NULL, '北京市海淀区永泰庄北路1号天地邻枫2号楼2层208', NULL, NULL, NULL, 'http://www.everlifebiomed.com/', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '华卫恒源于2018年在北京注册成立，拥有博士后科研工作站资质，是一家清华优秀科技成果转化落地企业。公司立足国际首创、具有完全自主知识产权的人源免疫豁免细胞技术，聚焦自身免疫病、再生医学领域、辅助生殖领域创新细胞药物和检测技术的研发。现有类风湿关节炎细胞注射液、免疫豁免人工胰腺和辅助生殖检测系统等项目，相关产品已进入临床前动物试验和人体临床试验备案阶段。', '2024-06-28 12:44:00', '2024-06-28 12:44:00', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1461, '武栋成', NULL, NULL, NULL, '武汉东湖新技术开发区神墩四路666号E区1号楼1层北、2层', NULL, NULL, NULL, 'http://www.hmdcell.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司由武栋成博士领衔的核心团队拥有干细胞制备核心发明专利；两个干细胞新药临床研究项目在国家卫健委完成备案并启动临床研究；2020年9月建成目前在全国名列前茅的GMP标准干细胞制剂制备、质量检测、储存中心，是华中区域规模最大的细胞治疗研发平台和干细胞药物中试平台。', '2024-06-28 13:27:41', '2024-06-28 13:27:41', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1462, '李翔', NULL, NULL, NULL, '中国（江苏）自由贸易试验区苏州片区苏州工业园区金谷路99号生物医药产业园三期B区项目3号楼201单元', NULL, NULL, NULL, 'http://www.xellsmart.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '士泽生物已建立完成iPS细胞株重编程、iPSC基因编辑和iPSC向不同亚型细胞类型诱导分化等领先的关键技术平台，并布局了全球技术专利体系；建立完成了GMP级别的iPSC细胞株；建设完成了细胞药物安全性和有效性评价的动物模型。士泽生物iPS分化为多巴胺神经前体细胞治疗帕金森病的核心管线预计2024年进入临床阶段。', '2024-06-28 16:50:53', '2024-06-28 16:50:53', 'SYSTEM', 'SYSTEM');
