VALUES (SPN-1463, '陈丽娟', NULL, NULL, NULL, '中国（上海）自由贸易试验区华申路215号D单元4层', NULL, NULL, NULL, 'http://36.138.223.14', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '跃赛生物首发管线—用于治疗帕金森病的中脑多巴胺能神经前体细胞药物，目前正快速推进IIT试验以及临床注册试验。', '2024-06-28 16:56:55', '2024-06-28 16:56:55', 'SYSTEM', 'SYSTEM');
