VALUES (SPN-1464, '龚伟', NULL, NULL, NULL, '天津经济技术开发区第四大街80号天大科技园B3座101室', NULL, NULL, NULL, 'https://www.amcellgene.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '天津昂赛细胞基因工程有限公司成立于2004年,主要从事干细胞药物研发、再生医疗相关组织工程产品以及细胞质量评价技术开发。截止到2024年1月，公司研发的干细胞新药已有5个适应症获得国家药品监督管理局药品审评中心临床试验默示许可。', '2024-06-28 17:01:28', '2024-06-28 17:01:28', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1465, '杜为', NULL, NULL, NULL, '天津市滨海高新区华苑产业区梅苑路12号【A】座二层房屋', NULL, NULL, NULL, 'www.vcanbio.com', '4', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司干细胞药物申报取得突破性进展，公司旗下自主研发的VUM02注射液（人脐带源间充质干细胞注射液）六个适应症已经进入临床试验阶段，在国内申报企业中处于第一梯队；参股公司与首都医科大学共同申报的“人牙髓间充质干细胞注射液”治疗慢性牙周炎已进入Ⅱ期临床试验阶段；合源生物的纳基奥仑赛注射液上市，这是首款具有中国全自主知识产权CD19 CAR-T细胞治疗产品，也是首款中国白血病治疗领域CAR-T细胞治疗产品。', '2024-06-28 17:05:19', '2024-06-28 17:05:19', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1466, '杨林', NULL, NULL, NULL, '苏州工业园区星湖街218号生物纳米园B1楼413单元', NULL, NULL, NULL, 'https://www.persongen.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '博生吉是一家专注于开发尖端细胞疗法的生物科技公司。该公司致力于开发与CAR相关的治疗和分析抗体、新型CAR产品和同种异体细胞疗法。公司开发了全面的产品管线和世界领先的同种异体现成UCAR-Vδ1 T细胞研发平台。', '2024-06-28 17:09:16', '2024-06-28 17:09:16', 'SYSTEM', 'SYSTEM');
