VALUES (SPN-1468, '无锡华泰创新药技术研究院有限公司', NULL, NULL, NULL, '江苏省-无锡市-惠山经济开发区惠山大道1699号c6楼二层', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', NULL, '2024-06-28 18:29:33', '2024-06-28 18:29:33', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1469, '赵辉', NULL, NULL, NULL, '北京市昌平区生命科学园生命园路20号院7号楼3层', NULL, NULL, NULL, 'www.unicetbio.com', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '北京清辉联诺是一家基于新型免疫细胞-γδT细胞开发创新性免疫药物的生物技术公司，致力于全面挖掘γδT/BTN免疫机制在癌症、感染性疾病的自身免疫疾病的治疗潜力。目前公司围绕γδT细胞已布局异体现货型细胞药、新靶点小分子药、新靶点抗体药等研发管线，已推进3款异体细胞治疗药物进入人体实验研究阶段，在脑肿瘤、肝癌、急性髓系白血病等领域证明了γδT细胞强大的治疗潜力。', '2024-07-05 13:28:27', '2024-07-05 13:28:27', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1470, '金洋帆', NULL, NULL, NULL, '长春市高新区硅谷大街3355号超达创业园2幢101、102、103号房', NULL, NULL, NULL, 'http://www.jlszksw.com.cn', '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '吉林省中科生物工程股份有限公司成立于2007年，是一家从事干细胞、免疫细胞研发与技术服务的国家级高新技术企业，以细胞的研发、临床转化为切入点，与中科院金宁一院士合作创办“院士工作站”，聘请哥伦比亚大学终身教授、国家“千人计划”专家杨永广教授担任免疫治疗项目首席专家；开展了数十项具有国际先进水平的科学研究，取得丰硕成果，拥有多项专利及专有技术；研发了胚胎干细胞、神经干细胞、羊膜干细胞、脂肪干细胞、脐带干细胞、DC-CIK细胞、NK细胞等十余种中科干细胞及免疫细胞，在治疗肿瘤、糖尿病、神经损伤、自身免疫系统疾病等方面取得了确切的疗效。', '2024-07-05 13:37:57', '2024-07-05 13:37:57', 'SYSTEM', 'SYSTEM');
