VALUES (SPN-1492, '北京鼎成肽源生物技术有限公司', NULL, NULL, NULL, '北京市昌平区双营西路86号院4号楼1至5层1单元101', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '北京鼎成肽源生物技术有限公司（简称“鼎成肽源”）成立于2014年3月，是以免疫细胞治疗产品研发和成果转化为主的“双高新”技术企业、北京市“专精特新” 中小企业、中关村金种子企业，北京市级企业科研机构，设立免疫学博士后科研工作站。围绕靶点发现、序列发现、序列评价和功能增强等环节，搭建独立自主的核心技术平台，进行TCR-T、TCR蛋白药和CAR-T细胞治疗产品的开发。', '2024-09-07 23:26:22', '2024-09-07 23:26:22', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1493, '北京卡替医疗', NULL, NULL, NULL, '北京市北京经济技术开发区科创六街88号院6号楼2单元501室', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '北京卡替(Chineo)医疗公司的核心研发团队由行业里的顶级科学家和临床研究专家组成，已在TIL/新抗原等创新免疫细胞治疗技术上深耕多年。卡替医疗自主研发的“超强型TIL”免疫细胞治疗技术，是目前处于国际最前沿的TIL和CAR-T等技术基础上的“青出于蓝”的重大升级。目前卡替医疗公司的“超强型TIL”细胞治疗产品已完成IND申报', '2024-09-07 23:41:07', '2024-09-07 23:41:07', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1494, '深圳莱芒生物', NULL, NULL, NULL, '深圳市福田区福保街道福保社区海红道1号综合信兴一期三层320-A、320-D', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '深圳莱芒生物科技有限公司是一家处于临床阶段的免疫代谢治疗药物研发公司，由瑞士洛桑联邦理工学院唐力教授团队联合晶泰科技共同创立。基于免疫代谢重编程+前沿人工智能的创新技术，公司专注于研发、生产和商业化新型肿瘤免疫治疗药物。', '2024-09-07 23:49:09', '2024-09-07 23:49:09', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1495, '沃昕生物科技（深圳）有限公司', NULL, NULL, NULL, '深圳市宝安区新安街道兴东社区67区大仟工业厂区宿舍105、106', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '沃昕生物科技（深圳）有限公司（简称“沃昕生物”）成立于2016年，是一家致力于肿瘤免疫治疗技术研发及技术服务、肿瘤治疗中心投资与管理的技术企业。沃昕生物拥有先进的研发平台、严格的细胞质量管理标准、高效的市场开发团队和完善的运营管理体系。', '2024-09-07 23:57:02', '2024-09-07 23:57:02', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1496, '重庆精准生物技术有限公司', NULL, NULL, NULL, '重庆市九龙坡区含谷镇含兴路38号', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '公司作为硬核科技创新型企业，掌握细胞领域关键技术，拥有多项授权发明专利，并在发达国家和地区进行了专利布局；公司实施推进了白血病、淋巴瘤、骨髓瘤、肠胃癌、肺癌、肝癌、乳腺癌、胰腺癌等10余项CAR-T研发管线，获得四个CAR-T细胞一类生物新药、九项适应症的默示许可，国内首个自主研发治疗儿童白血病的pCAR-19B细胞自体回输制剂（普基仑赛注射液）获准纳入“突破性治疗品种”、“优先审评品种”，2024年提交上市申请并于7月获国家药监局受理。同时，公司实现了CAR-T治疗肾癌、结直肠癌、胃癌等实体瘤技术的突破，相关产品获批注册临床，正积极推进药物注册临床。', '2024-09-08 00:05:00', '2024-09-08 00:05:00', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1497, '北京循生生物医学', NULL, NULL, NULL, '北京市大兴区天华大街33号院5号楼三层301', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '循生医学是一家以肿瘤免疫治疗研究为核心的创新生物医药公司，致力于研发新型个体化肿瘤免疫治疗产品。公司和国内外科学家携手，瞄准最前沿的免疫治疗技术，为全球病患提供更为安全、有效的创新药物和治疗方案。', '2024-09-08 00:11:38', '2024-09-08 00:11:38', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1498, '厦门诺康得生物科技有限公司', NULL, NULL, NULL, '厦门市翔安区民安街道莲亭路811号301单元-3', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '厦门诺康得生物科技有限公司是国际领先的基于糖化学生物学（cabonhydrate biochemistry）的新药研发公司。糖化学生物学在体内免疫中发挥重要作用。诺康得和厦门大学、美国密歇根州立大学等深入合作，设立海内外研发中心。相关技术处于国际一流水平。诺康得在巨噬细胞、NK细胞新型免疫检查点抑制剂、基于化学法而不是基因、病毒方法的细胞治疗（CECT）、糖基化乳腺癌癌症疫苗等领域均取得了卓越的成果。', '2024-09-08 00:19:05', '2024-09-08 00:19:05', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1499, '英百瑞（杭州）', NULL, NULL, NULL, '浙江省杭州市滨江区长河街道长江路365号32幢101室', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '英百瑞成立于2014年，从事肿瘤和免疫类疾病的治疗，2016年专注于创新型通用现货CAR-NK细胞疗法的开发，通过其原创的技术平台，研发出一系列细胞和抗体药物，致力于解决临床未满足的疾病，多个产品管线正在同步推向临床。', '2024-09-08 00:22:29', '2024-09-08 00:22:29', 'SYSTEM', 'SYSTEM');
