VALUES (SPN-1500, '上海精缮生物科技有限责任公司', NULL, NULL, NULL, '上海市虹口区中山北一路1111号1号楼1层101室', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '上海精缮生物科技有限责任公司（“精缮科技”）自主研发的细胞和基因治疗产品GC101（“该产品”）的临床试验申请于近日获国家药品监督管理局批准。该产品为1类治疗用生物制品（创新型生物制品），可用于隐性营养不良型大疱性表皮松解症。', '2024-09-08 00:28:39', '2024-09-08 00:28:39', 'SYSTEM', 'SYSTEM');
INSERT INTO sponsor_master (sponsor_id, sponsor_name, short_name, credit_code, legal_person, registered_address, office_address, contact_phone, contact_email, website, sponsor_type, is_listed, stock_code, vip_level, rating, drug_pipeline, project_count, contract_count, total_contract_amount, total_collection, sponsor_status, remark, created_at, updated_at, created_by, updated_by)
VALUES (SPN-1501, '深圳市先康达生命科学有限公司', NULL, NULL, NULL, '深圳市坪山区坑梓街道金沙社区青兰三路24号威尔德工业园厂房1栋503', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '深圳先康达生命科学有限公司（简称“先康达生命”）成立于2020年3月，是一家专注于实体瘤细胞免疫疗法研究及产业化的高新技术企业，布局了2大主流细胞治疗，T（CAR-T，CAR-iT）和NK（PANK，CAR-NK）。公司开发了3个具有自主知识产权的技术平台：Trans-CAR、Boost-CAR，R-Star，以及2大针对NK的工艺平台：hNK.LV和FCF-NK，在多家三甲医院开展了实体瘤CAR-T及PANK的临床研究，相关数据已初步显示出可控的安全性和良好的临床疗效。', '2024-09-08 00:34:08', '2024-09-08 00:34:08', 'SYSTEM', 'SYSTEM');
