VALUES (SPN-1510, '上海贝斯昂科', NULL, NULL, NULL, '中国（上海）自由贸易试验区金苏路200号、冀桥路700号23幢1楼', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '成立于2021年的贝斯生物是一家专注于基因编辑底层创新的科技型中小企业，在全球碱基编辑和细胞基因药物研发领域处于领先地位。我们致力于开发具有国际首创性的细胞治疗和基因编辑产品，尤其在癌症和遗传疾病治疗领域展现出巨大的潜力，成立于2021年的贝斯生物是一家专注于基因编辑底层创新的科技型中小企业，在全球碱基编辑和细胞基因药物研发领域处于领先地位。我们致力于开发具有国际首创性的细胞治疗和基因编辑产品，尤其在癌症和遗传疾病治疗领域展现出巨大的潜力', '2024-12-03 16:23:02', '2024-12-03 16:23:02', 'SYSTEM', 'SYSTEM');
