VALUES (SPN-1513, '深圳市茵冠生物科技有限公司', NULL, NULL, NULL, '深圳市茵冠生物科技有限公司', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', '深圳市茵冠生物科技有限公司是一家致力于细胞与基因治疗领域，聚焦于干细胞创新药物及联合疗法，集研究、开发、转化及应用的高科技企业，公司提供细胞治疗及基因治疗全产业链产业化服务，以干细胞临床研究与转化应用、癌症的细胞生物治疗、基因治疗、细胞储存、健康管理及公共技术服务平台等为主要业务，致力于将茵冠生物打造成集技术与服务为一体的国内顶尖、国际一流医疗健康服务集团。', '2024-12-03 17:31:50', '2024-12-03 17:31:50', 'SYSTEM', 'SYSTEM');
