VALUES (SPN-1519, '上海恩凯', NULL, NULL, NULL, '浦东新区周浦镇半夏路100弄7号全幢', NULL, NULL, NULL, NULL, '2', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE', 'NK CellTech 是一家专注于 NK 细胞疗法创新技术的发现和开发的生物技术公司。研发团队在NK细胞的研究和临床实践方面拥有超过30年的经验，致力于成为国际领先的细胞免疫治疗公司。凭借我们的ABCDE-NK&#174;平台（同种异体、血源性、现成冷冻保存、按需基因设计、扩展到临床规模）和SynNKTM 平台（合成免疫学的遗传学门技术），NK CellTech将提供创新的细胞药物，以精确靶向更广泛的肿瘤，并利用对肿瘤免疫微环境（TIME）的适应性，从而持续开发“智能”NK细胞产品，以解决未满足的临床需求的癌症患者。', '2025-02-28 17:31:59', '2025-02-28 17:31:59', 'SYSTEM', 'SYSTEM');
